mapper.select:
/* 포인트 환전: 회원 등록 계좌 조회 */
SELECT USR_BANK_NM AS bankNm,
       USR_ACNT_NO AS acntNo
FROM USERS
WHERE USR_SN = #{usrSn}

mapper.update:
/* 포인트 환전 주문: 지급 완료 처리 */
UPDATE POINT_EXCHANGE_ORDER
SET PT_EXC_ORD_STATUS_CD = #{statusCd},
    PT_EXC_ORD_PROC_USR_SN = #{procUsrSn},
    PT_EXC_ORD_PROC_DT = NOW()
WHERE PT_EXC_ORD_SN = #{ptExcOrdSn}

/* 포인트 환전 주문: 반려 처리 */
UPDATE POINT_EXCHANGE_ORDER
SET PT_EXC_ORD_STATUS_CD = #{statusCd},
    PT_EXC_ORD_PROC_USR_SN = #{procUsrSn},
    PT_EXC_ORD_PROC_DT = NOW(),
    PT_EXC_ORD_RESTORE_LDG_SN = #{restoreLdgSn},
    PT_EXC_ORD_RJCT_RSN_CN = #{rejectReason}
WHERE PT_EXC_ORD_SN = #{ptExcOrdSn}
